// 1. Get Malaysia time and timestamp
const timeSettings = { timeZone: 'Asia/Kuala_Lumpur', hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' };
const currentTime = new Date().toLocaleTimeString("en-GB", timeSettings);
const currentTimestamp = Date.now(); // Used to calculate parking duration

let deviceName = msg.topic || "Unknown";
let payloadStr = (msg.payload != null) ? msg.payload.toString().trim() : "";
let actionStatus = "";
let remark = "Live Update"; // Default remark

// 2. Core Logic (Added HTML Color Codes) --------------------------------
if (msg.topic.includes("parking/slot/")) {
    let slotNum = msg.topic.slice(-1); // Extract slot number
    deviceName = "Parking Slot " + slotNum;

    if (payloadStr === "1" || payloadStr === "Occupied") {
        actionStatus = "<span style='color:#3498db; font-weight:bold;'>🚗 Vehicle Arrived</span>";
        // Store arrival time
        flow.set("slot" + slotNum + "_arrive", currentTimestamp);
    }
    else if (payloadStr === "0" || payloadStr === "Empty") {
        actionStatus = "<span style='color:#2ecc71; font-weight:bold;'>🔓 Slot Empty</span>";
        let arriveTime = flow.get("slot" + slotNum + "_arrive");
        if (arriveTime) {
            let durationMs = currentTimestamp - arriveTime;
            let durationMins = Math.floor(durationMs / 60000);
            let durationSecs = Math.floor((durationMs % 60000) / 1000);

            // 🌟 Fully English formatted string with styling
            remark = `<span style='background-color:#e8f4f8; color:#2980b9; padding:2px 6px; border-radius:4px; font-weight:bold; border:1px solid #bdc3c7;'>⏱️ Parked: ${durationMins}m ${durationSecs}s</span>`;

            flow.set("slot" + slotNum + "_arrive", null); // Clear arrival time
        }
    }
}
else if (msg.topic === "parking/smoke/value") {
    deviceName = "Smoke Detector";
    if (payloadStr === "smoke") actionStatus = "<span style='color:red; font-weight:bold; font-size:14px;'>🔥 FIRE DETECTED</span>";
    else if (payloadStr === "clear") actionStatus = "<span style='color:#27ae60;'>✅ Smoke Cleared</span>";
}
else if (msg.topic === "system/auth") {
    deviceName = "Security Portal";
    actionStatus = "<span style='color:#9b59b6; font-weight:bold;'>🔐 " + payloadStr + "</span>";
    remark = "System Access Granted";
}
else if (msg.topic === "parking/alarm/status") {
    deviceName = "Emergency System";
    if (payloadStr === "panic") actionStatus = "<span style='color:#8e44ad; font-weight:bold;'>🚨 PANIC BUTTON PRESSED</span>";
    else if (payloadStr === "clear") actionStatus = "<span style='color:#27ae60;'>✅ Alarm Reset by Admin</span>";
}
else if (msg.topic === "parking/buzzer/control") {
    deviceName = "Admin Console";
    if (payloadStr === "OFF") actionStatus = "<span style='color:#e67e22;'>🔕 Buzzer Muted</span>";
}
else if (msg.topic === "parking/gate/control") {
    deviceName = "Admin Console";
    if (payloadStr === "OPEN") actionStatus = "<span style='color:#f39c12; font-weight:bold;'>🚧 Gate Opened</span>";
    else if (payloadStr === "CLOSE") actionStatus = "<span style='color:#7f8c8d; font-weight:bold;'>🚧 Gate Closed</span>";
}

// Filter out irrelevant noise/messages
if (actionStatus === "") return null;

// 3. Generate data for Table UI (with HTML colors)
const newLogEntry = {
    "Time": currentTime,
    "Device": deviceName,
    "Status": actionStatus,
    "Remark": remark
};

let eventHistory = flow.get("eventLogs") || [];
eventHistory.unshift(newLogEntry);
if (eventHistory.length > 20) eventHistory.pop(); // Keep top 20 records
flow.set("eventLogs", eventHistory);

// 4. Generate data for Firebase (Strip HTML tags to keep database clean)
let cleanStatus = actionStatus.replace(/<[^>]*>?/gm, '');
let cleanRemark = remark.replace(/<[^>]*>?/gm, ''); // 🌟 Clean the remark too

const firebaseEntry = {
    "Time": currentTime,
    "Device": deviceName,
    "Status": cleanStatus,
    "Remark": cleanRemark
};

// Output 1 (msg1) goes to UI Table, Output 2 (msg2) goes to Firebase
let msg1 = { payload: JSON.parse(JSON.stringify(eventHistory)) };
let msg2 = { payload: firebaseEntry };

return [msg1, msg2];
